html:
{%- set vcl_blue = '#2B3990' -%}
{%- set vcl_sage = '#7D9B76' -%}
{%- set vcl_bg = '#F5F6FA' -%}
{%- set transitions = frappe.get_all('Comment', filters={'reference_doctype': 'VCL Credit Note Request', 'reference_name': doc.name, 'comment_type': 'Workflow'}, fields=['owner', 'creation', 'content'], order_by='creation asc') -%}
{%- macro copy_block(copy_label) -%}
<div class="cn-copy">
  {% if doc.docstatus == 0 %}
  <div class="watermark">DRAFT</div>
  {% endif %}
  <div class="header">
    <div class="brand">
      <div class="brand-strip"></div>
      <div class="brand-text">
        <div class="brand-name">VIMIT CONVERTERS LIMITED</div>
        <div class="brand-tag">Credit Note Request</div>
      </div>
    </div>
    <div class="copy-label">{{ copy_label }}</div>
  </div>

  <div class="meta">
    <div><span class="k">CN No.</span><span class="v">{{ doc.name }}</span></div>
    <div><span class="k">Status</span><span class="v">{{ doc.status }}</span></div>
    <div><span class="k">Request Date</span><span class="v">{{ frappe.utils.formatdate(doc.request_date) }}</span></div>
  </div>

  <div class="two-col">
    <div class="col">
      <div class="col-title">Customer</div>
      <div class="row"><span class="k">Name</span><span class="v">{{ doc.customer or '' }}</span></div>
      <div class="row"><span class="k">Account Code</span><span class="v">{{ doc.account_code or '' }}</span></div>
      <div class="row"><span class="k">Contact</span><span class="v">{{ doc.contact_person or '' }}</span></div>
      <div class="row"><span class="k">Phone</span><span class="v">{{ doc.phone or '' }}</span></div>
      <div class="row"><span class="k">Email</span><span class="v">{{ doc.email or '' }}</span></div>
      <div class="row"><span class="k">Address</span><span class="v">{{ doc.delivery_address or '' }}</span></div>
      <div class="row"><span class="k">Credit Terms</span><span class="v">{{ doc.credit_terms or '' }}</span></div>
    </div>
    <div class="col">
      <div class="col-title">Transaction</div>
      <div class="row"><span class="k">Original Invoice</span><span class="v">{{ doc.original_invoice_no or '' }}</span></div>
      <div class="row"><span class="k">Invoice Date</span><span class="v">{{ frappe.utils.formatdate(doc.invoice_date) if doc.invoice_date else '' }}</span></div>
      <div class="row"><span class="k">KRA CU Invoice</span><span class="v">{{ doc.kra_cu_invoice_no or '' }}</span></div>
      <div class="row"><span class="k">Sales Rep</span><span class="v">{{ doc.sales_representative or '' }}</span></div>
      <div class="row"><span class="k">Root Cause</span><span class="v">{{ doc.root_cause or '' }}</span></div>
      <div class="row"><span class="k">Complaint Ref</span><span class="v">{{ doc.complaint_ref or '' }}</span></div>
      <div class="row"><span class="k">Action Required</span><span class="v">{{ doc.action_required or '' }}</span></div>
    </div>
  </div>

  {% if doc.detailed_reason %}
  <div class="notes">
    <div class="col-title">Detailed Reason</div>
    <div class="notes-body">{{ doc.detailed_reason }}</div>
  </div>
  {% endif %}

  <table class="items">
    <thead>
      <tr>
        <th class="desc">Description</th>
        <th class="num">Supp. Qty</th>
        <th class="uom">UOM</th>
        <th class="num">Supp. Rate</th>
        <th class="num">Supp. Amt</th>
        <th class="num">Corr. Qty</th>
        <th class="uom">UOM</th>
        <th class="num">Corr. Rate</th>
        <th class="num">Corr. Amt</th>
        <th class="num">Diff</th>
      </tr>
    </thead>
    <tbody>
      {% for it in doc.line_items %}
      <tr>
        <td class="desc">{{ it.description or '' }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.supplied_qty or 0) }}</td>
        <td class="uom">{{ it.supplied_uom or '' }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.supplied_unit_price or 0) }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.supplied_amount or 0) }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.correct_qty or 0) }}</td>
        <td class="uom">{{ it.correct_uom or '' }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.correct_unit_price or 0) }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.correct_amount or 0) }}</td>
        <td class="num">{{ '{:,.2f}'.format(it.difference or 0) }}</td>
      </tr>
      {% endfor %}
    </tbody>
  </table>

  <div class="totals-row">
    <div class="totals">
      <div class="row"><span class="k">Subtotal Supplied</span><span class="v">KES {{ '{:,.2f}'.format(doc.subtotal_supplied or 0) }}</span></div>
      <div class="row"><span class="k">Subtotal Correct</span><span class="v">KES {{ '{:,.2f}'.format(doc.subtotal_correct or 0) }}</span></div>
      <div class="row"><span class="k">VAT 16%</span><span class="v">KES {{ '{:,.2f}'.format(doc.vat_amount or 0) }}</span></div>
      <div class="row total"><span class="k">Total Credit</span><span class="v">KES {{ '{:,.2f}'.format(doc.total_credit or 0) }}</span></div>
    </div>
  </div>

  <div class="sigs">
    <div class="sig">
      <div class="sig-title">Raised By</div>
      <div class="sig-name">{{ doc.owner or '' }}</div>
      <div class="sig-date">{{ frappe.utils.format_datetime(doc.creation) }}</div>
    </div>
    {% for t in transitions %}
    <div class="sig">
      <div class="sig-title">{{ t.content or 'Workflow' }}</div>
      <div class="sig-name">{{ t.owner or '' }}</div>
      <div class="sig-date">{{ frappe.utils.format_datetime(t.creation) }}</div>
    </div>
    {% endfor %}
  </div>

  {% if doc.linked_credit_note %}
  <div class="footer-link">ERPNext Credit Note: <strong>{{ doc.linked_credit_note }}</strong></div>
  {% endif %}
</div>
{%- endmacro -%}

<style>
  .print-format { font-family: 'Helvetica Neue', Arial, sans-serif; color: #1f2330; font-size: 9pt; }
  .cn-copy { position: relative; padding: 14px 18px; border: 1px solid #d5d8e0; border-radius: 6px; background: #fff; margin-bottom: 10px; }
  .cn-copy .watermark { position: absolute; top: 40%; left: 0; right: 0; text-align: center; font-size: 84pt; color: rgba(229, 90, 90, 0.10); transform: rotate(-22deg); letter-spacing: 8px; font-weight: 800; pointer-events: none; z-index: 0; }
  .cn-copy .header { display: flex; align-items: stretch; justify-content: space-between; margin-bottom: 10px; }
  .cn-copy .brand { display: flex; align-items: stretch; }
  .cn-copy .brand-strip { width: 5px; background: #2B3990; margin-right: 10px; border-radius: 2px; }
  .cn-copy .brand-name { font-size: 13pt; font-weight: 700; color: #2B3990; letter-spacing: 0.5px; }
  .cn-copy .brand-tag { font-size: 9pt; color: #7D9B76; font-weight: 600; margin-top: 2px; letter-spacing: 0.4px; text-transform: uppercase; }
  .cn-copy .copy-label { background: #2B3990; color: #fff; padding: 4px 10px; font-weight: 700; font-size: 9pt; letter-spacing: 1.2px; height: fit-content; align-self: center; border-radius: 3px; }
  .cn-copy .meta { display: flex; gap: 28px; padding: 6px 0; border-top: 1px solid #ececf3; border-bottom: 1px solid #ececf3; margin-bottom: 10px; }
  .cn-copy .meta .k { color: #6b7080; margin-right: 6px; }
  .cn-copy .meta .v { font-weight: 600; }
  .cn-copy .two-col { display: flex; gap: 14px; margin-bottom: 8px; }
  .cn-copy .col { flex: 1; background: #F5F6FA; border-radius: 4px; padding: 8px 10px; }
  .cn-copy .col-title { font-weight: 700; color: #2B3990; font-size: 9pt; text-transform: uppercase; letter-spacing: 0.6px; margin-bottom: 4px; border-bottom: 1px solid #d5d8e0; padding-bottom: 3px; }
  .cn-copy .row { display: flex; justify-content: space-between; padding: 2px 0; font-size: 8.5pt; }
  .cn-copy .row .k { color: #6b7080; }
  .cn-copy .row .v { font-weight: 600; max-width: 60%; text-align: right; }
  .cn-copy .notes { margin: 6px 0 10px 0; padding: 8px 10px; background: #F5F6FA; border-left: 3px solid #7D9B76; border-radius: 2px; }
  .cn-copy .notes-body { font-size: 8.5pt; }
  .cn-copy table.items { width: 100%; border-collapse: collapse; margin-bottom: 8px; }
  .cn-copy table.items th { background: #2B3990; color: #fff; font-weight: 600; padding: 5px 6px; font-size: 8pt; text-align: left; }
  .cn-copy table.items td { border-bottom: 1px solid #ececf3; padding: 4px 6px; font-size: 8pt; }
  .cn-copy table.items td.num, .cn-copy table.items th.num { text-align: right; }
  .cn-copy table.items td.uom, .cn-copy table.items th.uom { text-align: center; }
  .cn-copy .totals-row { display: flex; justify-content: flex-end; }
  .cn-copy .totals { width: 280px; }
  .cn-copy .totals .row { padding: 3px 0; font-size: 9pt; }
  .cn-copy .totals .row.total { font-weight: 700; color: #2B3990; border-top: 1px solid #2B3990; margin-top: 4px; padding-top: 5px; font-size: 10pt; }
  .cn-copy .sigs { display: flex; gap: 12px; margin-top: 10px; flex-wrap: wrap; }
  .cn-copy .sig { flex: 1 1 22%; min-width: 130px; padding: 6px 8px; border: 1px dashed #d5d8e0; border-radius: 4px; background: #fff; }
  .cn-copy .sig-title { font-size: 7.5pt; color: #6b7080; text-transform: uppercase; letter-spacing: 0.6px; font-weight: 600; }
  .cn-copy .sig-name { font-weight: 700; color: #2B3990; margin-top: 2px; font-size: 9pt; }
  .cn-copy .sig-date { font-size: 7.5pt; color: #6b7080; margin-top: 1px; }
  .cn-copy .footer-link { margin-top: 6px; font-size: 8pt; color: #6b7080; text-align: right; }
  .cut-line { border-top: 1px dashed #6b7080; margin: 6px 0; text-align: center; font-size: 7.5pt; color: #6b7080; letter-spacing: 2px; }
  .cut-line span { background: #fff; padding: 0 8px; position: relative; top: -7px; }
</style>

{{ copy_block('ORIGINAL - FINANCE') }}
<div class="cut-line"><span>CUT HERE</span></div>
